import{_ as i,o as e,c as l,ag as n}from"./chunks/framework.BVZs_YW1.js";const u=JSON.parse('{"title":"Linux QQ 在 Wayland 下花屏：强制切到 Nvidia EGL","description":"","frontmatter":{},"headers":[],"relativePath":"notes/graphics/linuxqq-egl.md","filePath":"notes/graphics/linuxqq-egl.md"}'),s={name:"notes/graphics/linuxqq-egl.md"};function t(d,a,o,r,p,h){return e(),l("div",null,[...a[0]||(a[0]=[n('<h1 id="linux-qq-在-wayland-下花屏-强制切到-nvidia-egl" tabindex="-1">Linux QQ 在 Wayland 下花屏：强制切到 Nvidia EGL <a class="header-anchor" href="#linux-qq-在-wayland-下花屏-强制切到-nvidia-egl" aria-label="Permalink to &quot;Linux QQ 在 Wayland 下花屏：强制切到 Nvidia EGL&quot;">​</a></h1><p>症状一般长这样：</p><ul><li>QQ 原生 Wayland 启动</li><li>已经配过独显优先</li><li>但界面还是出现马赛克、撕裂或者明显异常</li></ul><p>这个问题在 Nvidia 机器上很容易误判成“桌面环境没配好”，其实根子通常不在桌面环境。</p><h2 id="原因" tabindex="-1">原因 <a class="header-anchor" href="#原因" aria-label="Permalink to &quot;原因&quot;">​</a></h2><p><code>libglvnd</code> 在选 <code>EGL</code> 供应者时，可能选到了 <code>mesa</code>，结果 QQ 实际走的是核显。</p><p>如果桌面环境本身已经在用独显渲染，这时就会出现大量跨卡数据拷贝。核显一旦顶不住，花屏和撕裂就都出来了。</p><h2 id="解决方法" tabindex="-1">解决方法 <a class="header-anchor" href="#解决方法" aria-label="Permalink to &quot;解决方法&quot;">​</a></h2><p>启动 QQ 时手动指定 Nvidia 的 EGL：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> __EGL_VENDOR_LIBRARY_FILENAMES=/usr/share/glvnd/egl_vendor.d/10_nvidia.json</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> linuxqq</span></span></code></pre></div><p>如果你经常用 QQ，最省事的做法是给它单独写一个启动器或者桌面项，不要每次手敲。</p>',11)])])}const _=i(s,[["render",t]]);export{u as __pageData,_ as default};
